    $inserted = 0;
    $skipped = 0;
    $errors = [];

    foreach ($newQuestions as $q) {
        $categoryName = $q[0];
        $categoryId = $categories[$categoryName] ?? null;

        if (!$categoryId) {
            $errors[] = "Category not found: $categoryName";
            continue;
        }

        // Check if question already exists
        $checkStmt = $conn->prepare("SELECT id FROM questions WHERE question = ?");
        $checkStmt->execute([$q[1]]);
        if ($checkStmt->fetch()) {
            $skipped++;
            continue;
        }

        $stmt = $conn->prepare("
            INSERT INTO questions (category_id, question, options, correct_answer, difficulty)
            VALUES (?, ?, ?, ?, ?)
        ");

        try {
            $stmt->execute([$categoryId, $q[1], $q[2], $q[3], $q[4]]);
            $inserted++;
        } catch (PDOException $e) {
            $errors[] = $q[1] . ': ' . $e->getMessage();
        }
    }

    // Count per category
    $stmt = $conn->query("SELECT c.name, COUNT(q.id) as total FROM categories c LEFT JOIN questions q ON c.id = q.category_id GROUP BY c.id, c.name ORDER BY c.name");
    $categoryCounts = $stmt->fetchAll(PDO::FETCH_ASSOC);

    $stmt = $conn->query("SELECT COUNT(*) as total FROM questions");
    $total = $stmt->fetch(PDO::FETCH_ASSOC)['total'];

    echo json_encode([
        'success' => true,
        'message' => "Added $inserted new questions, skipped $skipped duplicates",
        'total_questions' => $total,
        'categories' => $categoryCounts,
        'errors' => $errors
    ], JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE);

} catch (Exception $e) {
    echo json_encode([
        'success' => false,
        'error' => $e->getMessage()
    ]);
}
